script:
export const meta = { name: 'pass9-confirm-pii', description: 'Pass-9: re-confirm P9-PII-1 hostname remediation after the hook-wiring fix', phases: [{ title: 'Confirm' }] }
const REPO = '/Users/[REDACTED]/hc-assay'
const SCHEMA = { type: 'object', additionalProperties: false, required: ['verdict', 'appropriate', 'complete', 'rationale', 'concerns'], properties: { verdict: { type: 'string', enum: ['CONFIRMED', 'CONCERN', 'REJECTED'] }, appropriate: { type: 'boolean' }, complete: { type: 'boolean' }, rationale: { type: 'string' }, concerns: { type: 'array', items: { type: 'string' } } } }
const DESC = `P9-PII-1 (operator machine/namespace hostname leak) — ROUND 2 after a confirm-concern. The prior round CONFIRMED the machine hostname ([REDACTED], auto-derived) was scrubbed to 0, but found [REDACTED] was RE-INTRODUCED every commit because the pre-commit hook ran capture WITHOUT ASSAY_SCRUB_HOSTS, so _hostname_patterns() emitted no namespace rule. THE FIX NOW: .githooks/pre-commit exports ASSAY_SCRUB_HOSTS=hc-grc (honoring an external value) before invoking scripts/capture_transcripts.py; the corpus was re-scrubbed; _hostname_patterns() redacts the machine hostname bare+.local and an ASSAY_SCRUB_HOSTS host's .local form only (bare 'hc-grc' preserved). VERIFY on branch harden/pass-9: (1) grep transcripts/ for '[REDACTED]' AND '[REDACTED]' (case-insensitive) → expect 0 genuine leaks (a commit just re-captured the active session WITH the env, so it must stay 0); (2) bare 'hc-grc' still present (~1400, project token, not over-redacted); (3) the hook actually exports ASSAY_SCRUB_HOSTS before capture; (4) tests test_scrub_redacts_machine_and_namespace_hostnames + test_precommit_hook_wires_namespace_host_into_capture pass and discriminate. Is the operator-hostname PII vector now actually closed AND durable against future captures?`
function prompt(lens) { return `You are an independent adversarial fix-confirmation reviewer (reviewer ${lens}) for hc-assay at ${REPO} (branch harden/pass-9). Confirm the fix is appropriate AND complete (no residual gap; durable; tests discriminate). Read the files and grep the committed corpus yourself (git grep / grep -ri). Judge ONLY P9-PII-1.\n\n${DESC}` }
phase('Confirm')
const votes = (await parallel([
  () => agent(prompt('A'), { label: 'confirm:P9-PII-1:A', phase: 'Confirm', schema: SCHEMA }).then((v) => ({ lens: 'A', ...v })),
  () => agent(prompt('B'), { label: 'confirm:P9-PII-1:B', phase: 'Confirm', schema: SCHEMA }).then((v) => ({ lens: 'B', ...v })),
])).filter(Boolean)
const bothConfirmed = votes.length === 2 && votes.every((v) => v.verdict === 'CONFIRMED')
log(`P9-PII-1 round 2: ${bothConfirmed ? 'BOTH-CONFIRMED' : 'NEEDS-ATTENTION'} — ${votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
return { bothConfirmed, votes }
